-- Schema-per-PR isolation (PostgreSQL)
-- Run in your preview provisioning script, passing PR_NUMBER from CI.

-- Provision
CREATE SCHEMA IF NOT EXISTS pr_42;
SET search_path = pr_42, public;
-- (then run Flyway/Alembic migrations against this schema)

-- Verify isolation: confirm preview schema cannot see prod schema rows
SELECT table_schema, table_name
FROM information_schema.tables
WHERE table_schema = 'pr_42';

-- Teardown (called in the PR-close GitHub Actions job)
DROP SCHEMA IF EXISTS pr_42 CASCADE;

# vault/policies/genai-preview.hcl
# Vault policy for preview environment service accounts.
# Grants read access to preview-tier secrets only.

path "secret/data/genai/preview/*" {
  capabilities = ["read"]
}

# Explicitly deny production paths — even if a namespace escapes its policy.
path "secret/data/genai/prod/*" {
  capabilities = ["deny"]
}
path "secret/data/genai/staging/*" {
  capabilities = ["deny"]
}

# Deny real LLM API keys
path "secret/data/llm/openai/*" {
  capabilities = ["deny"]
}
path "secret/data/llm/anthropic/*" {
  capabilities = ["deny"]
}
